    [Test]
    public void GenerateMatchData_DealsFullDeckEvenly()
    {
      var matchData = new MatchInitializer().GenerateMatchData();

      Assert.That(matchData.Players.Length, Is.EqualTo(2));

      var allCards = new List<CardData>(52);
      foreach (var player in matchData.Players)
      {
        Assert.That(player.PlayDeck.Count, Is.EqualTo(26));
        Assert.That(player.SidePile.Count, Is.EqualTo(0));

        while (player.PlayDeck.Count > 0)
          allCards.Add(player.PlayDeck.Pop());
      }

      Assert.That(allCards.Count, Is.EqualTo(52));

      var unique = new HashSet<(CardRank Rank, CardSuit Suit)>();
      foreach (var card in allCards)
        unique.Add((card.Rank, card.Suit));

      Assert.That(unique.Count, Is.EqualTo(52));
    }

    [Test]
    public void GenerateMatchData_HasExactRankSuitDistribution()
    {
      var matchData = new MatchInitializer().GenerateMatchData();
      var rankCounts = new Dictionary<CardRank, int>();
      var suitCounts = new Dictionary<CardSuit, int>();

      foreach (var player in matchData.Players)
      {
        while (player.PlayDeck.Count > 0)
        {
          var card = player.PlayDeck.Pop();
          rankCounts[card.Rank] = rankCounts.TryGetValue(card.Rank, out var rankCount) ? rankCount + 1 : 1;
          suitCounts[card.Suit] = suitCounts.TryGetValue(card.Suit, out var suitCount) ? suitCount + 1 : 1;
        }
      }

      foreach (CardRank rank in System.Enum.GetValues(typeof(CardRank)))
        Assert.That(rankCounts[rank], Is.EqualTo(4));

      foreach (CardSuit suit in System.Enum.GetValues(typeof(CardSuit)))
        Assert.That(suitCounts[suit], Is.EqualTo(13));
    }

    [Test]
    public void ProcessTurn_WhenHigherCard_WinnerTakesBoth()
    {
      var matchData = new ServerMatchData();
      var processor = new MatchProcessor();

      // Top cards are the last pushed cards.
      matchData.Players[0].PlayDeck.Push(new CardData(CardRank.Ace, CardSuit.Spades));
      matchData.Players[1].PlayDeck.Push(new CardData(CardRank.Two, CardSuit.Clubs));

      var response = processor.ProcessTurn(matchData);

      Assert.That(matchData.Players[0].SidePile.Count, Is.EqualTo(2));
      Assert.That(matchData.Players[1].SidePile.Count, Is.EqualTo(0));
      Assert.That(matchData.Players[0].RevealedOnTable, Is.Null);
      Assert.That(matchData.Players[1].RevealedOnTable, Is.Null);
      Assert.That(response.MatchResult, Is.Not.Null);
      Assert.That(response.MatchResult.WinnerPlayerIdx, Is.EqualTo(0));
    }

    [Test]
    public void ProcessTurn_WhenMatchAlreadyFinished_DoesNothing()
    {
      var matchData = new ServerMatchData();
      var processor = new MatchProcessor();
      matchData.EndMatch(0);

      matchData.Players[0].PlayDeck.Push(new CardData(CardRank.Ace, CardSuit.Spades));
      matchData.Players[1].PlayDeck.Push(new CardData(CardRank.King, CardSuit.Hearts));

      var beforeTotal = CountAllCards(matchData);
      var response = processor.ProcessTurn(matchData);
      var afterTotal = CountAllCards(matchData);

      Assert.That(response.TurnEvents.Count, Is.EqualTo(0));
      Assert.That(beforeTotal, Is.EqualTo(afterTotal));
      Assert.That(matchData.Result.WinnerPlayerIdx, Is.EqualTo(0));
    }

    [Test]
    public void ProcessTurn_WhenWarOccurs_WinnerTakesAllWarCards()
    {
      var matchData = new ServerMatchData();
      var processor = new MatchProcessor();

      // Player 0: reveal K, 3 hidden, then reveal A.
      matchData.Players[0].PlayDeck.Push(new CardData(CardRank.Ace, CardSuit.Spades));
      matchData.Players[0].PlayDeck.Push(new CardData(CardRank.Two, CardSuit.Spades));
      matchData.Players[0].PlayDeck.Push(new CardData(CardRank.Three, CardSuit.Spades));
      matchData.Players[0].PlayDeck.Push(new CardData(CardRank.Four, CardSuit.Spades));
      matchData.Players[0].PlayDeck.Push(new CardData(CardRank.King, CardSuit.Spades));

      // Player 1: reveal K, 3 hidden, then reveal Q.
      matchData.Players[1].PlayDeck.Push(new CardData(CardRank.Queen, CardSuit.Hearts));
      matchData.Players[1].PlayDeck.Push(new CardData(CardRank.Two, CardSuit.Hearts));
      matchData.Players[1].PlayDeck.Push(new CardData(CardRank.Three, CardSuit.Hearts));
      matchData.Players[1].PlayDeck.Push(new CardData(CardRank.Four, CardSuit.Hearts));
      matchData.Players[1].PlayDeck.Push(new CardData(CardRank.King, CardSuit.Hearts));

      var response = processor.ProcessTurn(matchData);

      Assert.That(matchData.Players[0].SidePile.Count, Is.EqualTo(10));
      Assert.That(matchData.Players[1].SidePile.Count, Is.EqualTo(0));
      Assert.That(matchData.Players[0].HiddenOnTable.Count, Is.EqualTo(0));
      Assert.That(matchData.Players[1].HiddenOnTable.Count, Is.EqualTo(0));
      Assert.That(matchData.Players[0].RevealedOnTable, Is.Null);
      Assert.That(matchData.Players[1].RevealedOnTable, Is.Null);
      Assert.That(response.TurnEvents, Is.Not.Empty);
    }

