    [Test]
    public void ProcessTurn_EmitsExpectedEventSequence_ForSimpleTurn()
    {
      var matchData = new ServerMatchData();
      var processor = new MatchProcessor();

      matchData.Players[0].PlayDeck.Push(new CardData(CardRank.Ace, CardSuit.Spades));
      matchData.Players[1].PlayDeck.Push(new CardData(CardRank.Two, CardSuit.Clubs));

      var response = processor.ProcessTurn(matchData);
      var kinds = response.TurnEvents.Select(x => x.EventKind).ToArray();

      Assert.That(kinds.Length, Is.EqualTo(3));
      Assert.That(kinds[0], Is.EqualTo(TurnEventKind.RevealTopFromDeck));
      Assert.That(kinds[1], Is.EqualTo(TurnEventKind.RevealTopFromDeck));
      Assert.That(kinds[2], Is.EqualTo(TurnEventKind.PutToSidePile));
    }

