    [Test]
    public void UseSidePileAsDeck_TransfersCardsAndAllowsTurnProgress()
    {
      var matchData = new ServerMatchData();
      var processor = new MatchProcessor();

      matchData.Players[0].SidePile.Push(new CardData(CardRank.King, CardSuit.Spades));
      matchData.Players[0].SidePile.Push(new CardData(CardRank.Ace, CardSuit.Spades));
      matchData.Players[0].SidePile.Push(new CardData(CardRank.Queen, CardSuit.Spades));
      matchData.Players[1].PlayDeck.Push(new CardData(CardRank.Two, CardSuit.Clubs));

      var response = processor.ProcessTurn(matchData);

      Assert.That(ContainsEvent(response.TurnEvents, TurnEventKind.UseSidePileAsDeck), Is.True);
      Assert.That(matchData.Players[0].PlayDeck.Count, Is.GreaterThanOrEqualTo(0));
      Assert.That(matchData.Players[0].SidePile.Count, Is.GreaterThanOrEqualTo(0));
      Assert.That(CountAllCards(matchData), Is.EqualTo(4));
    }

