    [Test]
    public void ProcessTurn_NeverChangesTotalCardCount()
    {
      var matchData = new MatchInitializer().GenerateMatchData();
      var processor = new MatchProcessor();
      var initialCount = CountAllCards(matchData);

      for (var i = 0; i < 30 && matchData.Result == null; i++)
      {
        processor.ProcessTurn(matchData);
        Assert.That(CountAllCards(matchData), Is.EqualTo(initialCount));
      }
    }

    private static bool ContainsEvent(IEnumerable<Shared.SharedModel.Dto.TurnEventData> events, TurnEventKind kind)
    {
      foreach (var turnEvent in events)
        if (turnEvent.EventKind == kind)
          return true;

      return false;
    }

    private static int CountAllCards(ServerMatchData matchData)
    {
      var count = 0;
      foreach (var player in matchData.Players)
      {
        count += player.PlayDeck.Count;
        count += player.SidePile.Count;
        count += player.HiddenOnTable.Count;
        if (player.RevealedOnTable != null)
          count += 1;
      }

      return count;
    }
